import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom"; // ✅ ADDED
import Navbar from "../../components/Navbar";
import api from "../../api/axiosInstance";
import styles from "./UserPages.module.css";

const PackageDetailsPage = () => {
  const { id } = useParams();
  const navigate = useNavigate(); // ✅ ADDED

  // 🔥 PACKAGE DATA
  const [pkg, setPkg] = useState(null);
  const [loading, setLoading] = useState(true);

  // ⭐ REVIEW STATE
  const [reviews, setReviews] = useState([]);
  const [name, setName] = useState("");
  const [rating, setRating] = useState("⭐ ⭐ ⭐ ⭐ ⭐");
  const [comment, setComment] = useState("");

  // 🔄 FETCH PACKAGE
  useEffect(() => {
    api.get(`/packages/${id}`)
      .then((res) => setPkg(res.data.data))
      .catch((err) => console.error(err))
      .finally(() => setLoading(false));
  }, [id]);

  // ⭐ HANDLE REVIEW
  const handleSubmit = () => {
    if (!name || !comment) return;

    const newReview = { name, rating, comment };
    setReviews([newReview, ...reviews]);

    setName("");
    setComment("");
  };

  // ⏳ LOADING STATE
  if (loading) return <p>Loading...</p>;
  if (!pkg) return <p>Package not found</p>;

  return (
    <>
      <Navbar />

      <div className={styles.detailsContainer}>
        
        {/* HERO */}
        <div className={styles.detailsHero}>
          <h1>{pkg.name}</h1>
          <span className={styles.badge}>{pkg.duration}</span>
          <p>{pkg.description || "Enjoy your trip!"}</p>
        </div>

        {/* FEATURES */}
        <div className={styles.detailsGrid}>

          <div className={styles.detailCard}>
            <h3>🚗 Transportation</h3>
            <ul>
              {pkg.transportation?.length > 0 ? (
                pkg.transportation.map((t, i) => (
                  <li key={i}>{t}</li>
                ))
              ) : (
                <li>Not provided</li>
              )}
            </ul>
          </div>

          <div className={styles.detailCard}>
            <h3>🎡 Sightseeing</h3>
            <ul>
              {pkg.sightseeing?.length > 0 ? (
                pkg.sightseeing.map((s, i) => (
                  <li key={i}>{s}</li>
                ))
              ) : (
                <li>Not provided</li>
              )}
            </ul>
          </div>

          <div className={styles.detailCard}>
            <h3>🍽 Meals</h3>
            <ul>
              {pkg.meals?.length > 0 ? (
                pkg.meals.map((m, i) => (
                  <li key={i}>{m}</li>
                ))
              ) : (
                <li>Not provided</li>
              )}
            </ul>
          </div>

        </div>

        {/* ITINERARY */}
        <div className={styles.itinerary}>
          <h2>🗓 Itinerary</h2>
          <ol>
            {pkg.itinerary?.length > 0 ? (
              pkg.itinerary.map((day, i) => (
                <li key={i}>{day}</li>
              ))
            ) : (
              <li>No itinerary available</li>
            )}
          </ol>
        </div>

        {/* ✅ HOTELS */}
        <h2>🏨 Available Hotels</h2>

        <div className={styles.hotelGrid}>
          {pkg.hotels && pkg.hotels.length > 0 ? (
            pkg.hotels.map((hotel, index) => (
              <div key={index} className={styles.hotelCard}>
                
                <img
                  src={
                    hotel.image ||
                    "https://images.unsplash.com/photo-1566073771259-6a8506099945"
                  }
                  alt={hotel.name}
                />

                <h4>{hotel.name}</h4>
                <p>₹{hotel.pricePerDay}</p>
                <p>{hotel.description}</p>

                {/* ✅ THIS IS THE MAIN FIX */}
                <button
                  onClick={() =>
                    navigate("/payment", {
                      state: {
                        package: pkg,
                        hotel: hotel,
                      },
                    })
                  }
                >
                  Select Hotel
                </button>

              </div>
            ))
          ) : (
            <p>No hotels available</p>
          )}
        </div>

        {/* ⭐ REVIEWS */}
        <div className={styles.reviews}>
          <h2>⭐ Customer Reviews</h2>

          <input
            type="text"
            placeholder="Your Name"
            className={styles.input}
            value={name}
            onChange={(e) => setName(e.target.value)}
          />

          <select
            className={styles.input}
            value={rating}
            onChange={(e) => setRating(e.target.value)}
          >
            <option>⭐ ⭐ ⭐ ⭐ ⭐</option>
            <option>⭐ ⭐ ⭐ ⭐</option>
            <option>⭐ ⭐ ⭐</option>
            <option>⭐ ⭐</option>
            <option>⭐</option>
          </select>

          <textarea
            placeholder="Write your experience..."
            className={styles.textarea}
            value={comment}
            onChange={(e) => setComment(e.target.value)}
          />

          <button className={styles.reviewBtn} onClick={handleSubmit}>
            Submit Review
          </button>

          {reviews.length === 0 ? (
            <p className={styles.noReview}>No reviews yet.</p>
          ) : (
            <div className={styles.reviewList}>
              {reviews.map((r, index) => (
                <div key={index} className={styles.reviewCard}>
                  <h4>{r.name}</h4>
                  <p>{r.rating}</p>
                  <p>{r.comment}</p>
                </div>
              ))}
            </div>
          )}
        </div>

      </div>
    </>
  );
};

export default PackageDetailsPage;
